CREATE TABLE IF NOT EXISTS stocks (id BIGSERIAL PRIMARY KEY, product_id BIGINT NOT NULL, product_code VARCHAR(40) NOT NULL, product_name VARCHAR(120) NOT NULL, warehouse_id BIGINT NOT NULL, warehouse_name VARCHAR(80) NOT NULL, current_quantity NUMERIC(12,2) NOT NULL, minimum_stock NUMERIC(12,2) NOT NULL, maximum_stock NUMERIC(12,2), updated_at TIMESTAMP NOT NULL, UNIQUE(product_id, warehouse_id));
CREATE TABLE IF NOT EXISTS purchase_orders (id BIGSERIAL PRIMARY KEY, order_number VARCHAR(30) NOT NULL UNIQUE, supplier_id BIGINT NOT NULL, supplier_name VARCHAR(120) NOT NULL, created_by VARCHAR(60) NOT NULL, status VARCHAR(20) NOT NULL, expected_date DATE, observations VARCHAR(500), created_at TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS purchase_order_lines (id BIGSERIAL PRIMARY KEY, purchase_order_id BIGINT NOT NULL REFERENCES purchase_orders(id) ON DELETE CASCADE, product_id BIGINT NOT NULL, product_code VARCHAR(40) NOT NULL, product_name VARCHAR(120) NOT NULL, ordered_quantity NUMERIC(12,2) NOT NULL, received_quantity NUMERIC(12,2) NOT NULL, unit_price NUMERIC(12,2) NOT NULL);
CREATE TABLE IF NOT EXISTS internal_requests (id BIGSERIAL PRIMARY KEY, request_number VARCHAR(30) NOT NULL UNIQUE, area_id BIGINT NOT NULL, area_name VARCHAR(80) NOT NULL, requested_by VARCHAR(60) NOT NULL, status VARCHAR(20) NOT NULL, observations VARCHAR(500), created_at TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS internal_request_lines (id BIGSERIAL PRIMARY KEY, internal_request_id BIGINT NOT NULL REFERENCES internal_requests(id) ON DELETE CASCADE, product_id BIGINT NOT NULL, product_code VARCHAR(40) NOT NULL, product_name VARCHAR(120) NOT NULL, requested_quantity NUMERIC(12,2) NOT NULL, approved_quantity NUMERIC(12,2) NOT NULL, dispatched_quantity NUMERIC(12,2) NOT NULL);
CREATE TABLE IF NOT EXISTS inventory_movements (id BIGSERIAL PRIMARY KEY, type VARCHAR(20) NOT NULL, origin VARCHAR(20) NOT NULL, warehouse_id BIGINT NOT NULL, warehouse_name VARCHAR(80) NOT NULL, responsible_user VARCHAR(60) NOT NULL, reference_number VARCHAR(30), observations VARCHAR(500), created_at TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS inventory_movement_lines (id BIGSERIAL PRIMARY KEY, inventory_movement_id BIGINT NOT NULL REFERENCES inventory_movements(id) ON DELETE CASCADE, product_id BIGINT NOT NULL, product_code VARCHAR(40) NOT NULL, product_name VARCHAR(120) NOT NULL, quantity NUMERIC(12,2) NOT NULL, unit_cost NUMERIC(12,2) NOT NULL, lot VARCHAR(50), expiration_date DATE);
CREATE TABLE IF NOT EXISTS audit_events (id BIGSERIAL PRIMARY KEY, action VARCHAR(80) NOT NULL, username VARCHAR(60) NOT NULL, description VARCHAR(500) NOT NULL, created_at TIMESTAMP NOT NULL);
